import{_ as e,o as l,c as i,ag as d}from"./chunks/framework.DTiDeF2Q.js";const g=JSON.parse(`{"title":"Fonctions | Dotfiles (FR)","titleTemplate":":title","description":"Fonctions shell qui améliorent votre expérience terminal. Utilitaires pour les API, les fichiers et les opérations système.","frontmatter":{"title":"Fonctions | Dotfiles","description":"Fonctions shell qui améliorent votre expérience terminal. Utilitaires pour les API, les fichiers et les opérations système.","lang":"fr-FR","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"Fonctions preview","canonical":"/fr/functions/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"Fonctions","pageType":"docs","schemaType":"WebPage","metaTitle":"Fonctions - Dotfiles (FR)","permalink":"/fr/functions/","meta":[{"name":"keywords","content":"fonctions, shell, bash, zsh, dotfiles, productivité, utilitaires, api, fichiers, système"},{"name":"twitter:card","content":"summary"},{"name":"twitter:description","content":"Fonctions shell qui améliorent votre expérience terminal. Utilitaires pour les API, les fichiers et les opérations système."},{"name":"twitter:title","content":"Fonctions - Dotfiles"},{"name":"og:title","content":"Fonctions - Dotfiles"},{"name":"og:description","content":"Fonctions shell qui améliorent votre expérience terminal. Utilitaires pour les API, les fichiers et les opérations système."},{"name":"og:image:alt","content":"Dotfiles - Conçus pour s'adapter à votre vie de shell"},{"name":"og:locale","content":"fr_FR"}]},"headers":[],"relativePath":"fr/functions/index.md","filePath":"fr/functions/index.md","lastUpdated":1773010926000}`),a={name:"fr/functions/index.md"};function s(o,t,n,r,c,f){return l(),i("div",null,[...t[0]||(t[0]=[d('<h1 id="fonctions" tabindex="-1">Fonctions <a class="header-anchor" href="#fonctions" aria-label="Permalink to &quot;Fonctions&quot;">​</a></h1><p>Utilitaires shell pour augmenter votre productivité sur macOS, Linux et Windows.</p><h2 id="decouvrir" tabindex="-1">Découvrir <a class="header-anchor" href="#decouvrir" aria-label="Permalink to &quot;Découvrir&quot;">​</a></h2><p>Les fonctions sont définies dans des fichiers <code>.sh</code> séparés. Lors de <code>chezmoi apply</code>, elles sont agrégées dans <code>~/.config/shell/functions.sh</code> puis chargées par votre shell.</p><h2 id="premiers-pas" tabindex="-1">Premiers pas <a class="header-anchor" href="#premiers-pas" aria-label="Permalink to &quot;Premiers pas&quot;">​</a></h2><h3 id="ajouter-une-fonction" tabindex="-1">Ajouter une fonction <a class="header-anchor" href="#ajouter-une-fonction" aria-label="Permalink to &quot;Ajouter une fonction&quot;">​</a></h3><ol><li>Créez un nouveau fichier <code>.sh</code> (par exemple <code>mafonction.sh</code>)</li><li>Ajoutez la définition de votre fonction</li><li>Appliquez les changements :<div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">chezmoi</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apply</span></span></code></pre></div></li></ol><h2 id="reference" tabindex="-1">Référence <a class="header-anchor" href="#reference" aria-label="Permalink to &quot;Référence&quot;">​</a></h2><h3 id="tests-d-api" tabindex="-1">Tests d’API <a class="header-anchor" href="#tests-d-api" aria-label="Permalink to &quot;Tests d’API&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Fonction</th><th style="text-align:left;">Description</th><th style="text-align:left;">Utilisation</th></tr></thead><tbody><tr><td style="text-align:left;"><code>apihealth</code></td><td style="text-align:left;">Vérifier la santé d’une ou plusieurs API</td><td style="text-align:left;"><code>apihealth [OPTIONS] URL [URL ...]</code></td></tr><tr><td style="text-align:left;"><code>apilatency</code></td><td style="text-align:left;">Mesurer la latence d’une API</td><td style="text-align:left;"><code>apilatency URL [COUNT] [INTERVAL]</code></td></tr><tr><td style="text-align:left;"><code>apiload</code></td><td style="text-align:left;">Effectuer un test de charge simple</td><td style="text-align:left;"><code>apiload URL [REQUESTS] [DELAY]</code></td></tr><tr><td style="text-align:left;"><code>httpdebug</code></td><td style="text-align:left;">Déboguer des requêtes HTTP avec timings</td><td style="text-align:left;"><code>httpdebug [options] [url]</code></td></tr></tbody></table><h3 id="utilitaires-http" tabindex="-1">Utilitaires HTTP <a class="header-anchor" href="#utilitaires-http" aria-label="Permalink to &quot;Utilitaires HTTP&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Fonction</th><th style="text-align:left;">Description</th><th style="text-align:left;">Utilisation</th></tr></thead><tbody><tr><td style="text-align:left;"><code>curlheader</code></td><td style="text-align:left;">Afficher les en-têtes HTTP</td><td style="text-align:left;"><code>curlheader [header] [url]</code></td></tr><tr><td style="text-align:left;"><code>curlstatus</code></td><td style="text-align:left;">Vérifier le code de statut HTTP</td><td style="text-align:left;"><code>curlstatus [url]</code></td></tr><tr><td style="text-align:left;"><code>curltime</code></td><td style="text-align:left;">Mesurer les métriques de timing HTTP</td><td style="text-align:left;"><code>curltime [url]</code></td></tr><tr><td style="text-align:left;"><code>view-source</code></td><td style="text-align:left;">Afficher le code source d’un site</td><td style="text-align:left;"><code>view-source URL</code></td></tr><tr><td style="text-align:left;"><code>whoisport</code></td><td style="text-align:left;">Trouver le processus qui utilise un port</td><td style="text-align:left;"><code>whoisport PORT</code></td></tr></tbody></table><h3 id="gestion-des-fichiers" tabindex="-1">Gestion des fichiers <a class="header-anchor" href="#gestion-des-fichiers" aria-label="Permalink to &quot;Gestion des fichiers&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Fonction</th><th style="text-align:left;">Description</th><th style="text-align:left;">Utilisation</th></tr></thead><tbody><tr><td style="text-align:left;"><code>backup</code></td><td style="text-align:left;">Créer des sauvegardes horodatées</td><td style="text-align:left;"><code>backup [--max-size SIZE] [--keep N] &lt;files...&gt;</code></td></tr><tr><td style="text-align:left;"><code>encode64</code> / <code>decode64</code></td><td style="text-align:left;">Encodage et décodage Base64</td><td style="text-align:left;"><code>encode64 &quot;string&quot;</code></td></tr><tr><td style="text-align:left;"><code>extract</code></td><td style="text-align:left;">Extraire des archives</td><td style="text-align:left;"><code>extract [file]</code></td></tr><tr><td style="text-align:left;"><code>hexdump</code></td><td style="text-align:left;">Afficher un fichier en hexadécimal</td><td style="text-align:left;"><code>hexdump [file] [lines]</code></td></tr><tr><td style="text-align:left;"><code>ren</code></td><td style="text-align:left;">Renommer des extensions par lot</td><td style="text-align:left;"><code>ren OLD_EXT NEW_EXT</code></td></tr><tr><td style="text-align:left;"><code>size</code></td><td style="text-align:left;">Vérifier la taille d’un fichier ou dossier</td><td style="text-align:left;"><code>size [file/directory]</code></td></tr><tr><td style="text-align:left;"><code>zipf</code></td><td style="text-align:left;">Créer des archives ZIP</td><td style="text-align:left;"><code>zipf [folder]</code></td></tr></tbody></table><h3 id="nommage-de-fichiers" tabindex="-1">Nommage de fichiers <a class="header-anchor" href="#nommage-de-fichiers" aria-label="Permalink to &quot;Nommage de fichiers&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Fonction</th><th style="text-align:left;">Description</th><th style="text-align:left;">Utilisation</th></tr></thead><tbody><tr><td style="text-align:left;"><code>kebabcase</code></td><td style="text-align:left;">Convertir en kebab-case</td><td style="text-align:left;"><code>kebabcase &lt;files...&gt;</code></td></tr><tr><td style="text-align:left;"><code>lowercase</code></td><td style="text-align:left;">Convertir en minuscules</td><td style="text-align:left;"><code>lowercase &lt;files...&gt;</code></td></tr><tr><td style="text-align:left;"><code>sentencecase</code></td><td style="text-align:left;">Convertir en casse phrase</td><td style="text-align:left;"><code>sentencecase &lt;files...&gt;</code></td></tr><tr><td style="text-align:left;"><code>snakecase</code></td><td style="text-align:left;">Convertir en snake_case</td><td style="text-align:left;"><code>snakecase &lt;files...&gt;</code></td></tr><tr><td style="text-align:left;"><code>titlecase</code></td><td style="text-align:left;">Convertir en Title Case</td><td style="text-align:left;"><code>titlecase &lt;files...&gt;</code></td></tr><tr><td style="text-align:left;"><code>uppercase</code></td><td style="text-align:left;">Convertir en MAJUSCULES</td><td style="text-align:left;"><code>uppercase &lt;files...&gt;</code></td></tr></tbody></table><h3 id="utilitaires-systeme" tabindex="-1">Utilitaires système <a class="header-anchor" href="#utilitaires-systeme" aria-label="Permalink to &quot;Utilitaires système&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Fonction</th><th style="text-align:left;">Description</th><th style="text-align:left;">Utilisation</th></tr></thead><tbody><tr><td style="text-align:left;"><code>caffeine</code></td><td style="text-align:left;">Empêcher la mise en veille</td><td style="text-align:left;"><code>caffeine [command]</code></td></tr><tr><td style="text-align:left;"><code>environment</code></td><td style="text-align:left;">Détecter l’environnement OS</td><td style="text-align:left;"><code>environment</code></td></tr><tr><td style="text-align:left;"><code>freespace</code></td><td style="text-align:left;">Nettoyer l’espace libérable</td><td style="text-align:left;"><code>freespace [disk]</code></td></tr><tr><td style="text-align:left;"><code>hiddenfiles</code></td><td style="text-align:left;">Afficher/masquer les fichiers cachés</td><td style="text-align:left;">`hiddenfiles [show</td></tr><tr><td style="text-align:left;"><code>hostinfo</code></td><td style="text-align:left;">Afficher les infos de l’hôte</td><td style="text-align:left;"><code>hostinfo</code></td></tr><tr><td style="text-align:left;"><code>hstats</code></td><td style="text-align:left;">Statistiques d’usage des commandes</td><td style="text-align:left;"><code>hstats</code></td></tr><tr><td style="text-align:left;"><code>last</code></td><td style="text-align:left;">Lister les fichiers récemment modifiés</td><td style="text-align:left;"><code>last [minutes]</code></td></tr><tr><td style="text-align:left;"><code>logout</code></td><td style="text-align:left;">Déconnexion multiplateforme</td><td style="text-align:left;"><code>logout [--force]</code></td></tr><tr><td style="text-align:left;"><code>myproc</code></td><td style="text-align:left;">Lister les processus utilisateur</td><td style="text-align:left;"><code>myproc</code></td></tr><tr><td style="text-align:left;"><code>stopwatch</code></td><td style="text-align:left;">Chronomètre terminal</td><td style="text-align:left;"><code>stopwatch</code></td></tr><tr><td style="text-align:left;"><code>sysinfo</code></td><td style="text-align:left;">Afficher les infos système</td><td style="text-align:left;"><code>sysinfo</code></td></tr></tbody></table><h3 id="commandes-caffeine" tabindex="-1">Commandes Caffeine <a class="header-anchor" href="#commandes-caffeine" aria-label="Permalink to &quot;Commandes Caffeine&quot;">​</a></h3><p>Empêche la mise en veille ou l’activation de l’économiseur d’écran.</p><table tabindex="0"><thead><tr><th style="text-align:left;">Commande</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;"><code>caffeine daemon</code></td><td style="text-align:left;">Démarrer le daemon caffeine</td></tr><tr><td style="text-align:left;"><code>caffeine status</code></td><td style="text-align:left;">Vérifier si le daemon tourne</td></tr><tr><td style="text-align:left;"><code>caffeine start</code></td><td style="text-align:left;">Garder l’écran éveillé</td></tr><tr><td style="text-align:left;"><code>caffeine stop</code></td><td style="text-align:left;">Autoriser la mise en veille</td></tr><tr><td style="text-align:left;"><code>caffeine toggle</code></td><td style="text-align:left;">Basculer l’écran éveillé</td></tr><tr><td style="text-align:left;"><code>caffeine shutdown</code></td><td style="text-align:left;">Arrêter le daemon</td></tr></tbody></table><p>Fonctionne sur macOS (<code>caffeinate</code>), Linux (<code>xdg-screensaver</code>) et Windows (PowerShell).</p><h3 id="securite" tabindex="-1">Sécurité <a class="header-anchor" href="#securite" aria-label="Permalink to &quot;Sécurité&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Fonction</th><th style="text-align:left;">Description</th><th style="text-align:left;">Utilisation</th></tr></thead><tbody><tr><td style="text-align:left;"><code>genpass</code></td><td style="text-align:left;">Générer des mots de passe robustes</td><td style="text-align:left;"><code>genpass [num_blocks] [separator]</code></td></tr><tr><td style="text-align:left;"><code>keygen</code></td><td style="text-align:left;">Générer des paires de clés SSH</td><td style="text-align:left;"><code>keygen [name] [email] [type] [bits]</code></td></tr></tbody></table><h3 id="navigation" tabindex="-1">Navigation <a class="header-anchor" href="#navigation" aria-label="Permalink to &quot;Navigation&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Fonction</th><th style="text-align:left;">Description</th><th style="text-align:left;">Utilisation</th></tr></thead><tbody><tr><td style="text-align:left;"><code>cdls</code></td><td style="text-align:left;">Changer de répertoire et lister</td><td style="text-align:left;"><code>cdls [directory]</code></td></tr><tr><td style="text-align:left;"><code>goto</code></td><td style="text-align:left;">Navigation rapide</td><td style="text-align:left;"><code>goto [directory]</code></td></tr><tr><td style="text-align:left;"><code>mount_read_only</code></td><td style="text-align:left;">Monter en lecture seule comme lecture/écriture</td><td style="text-align:left;"><code>mount_read_only [image]</code></td></tr><tr><td style="text-align:left;"><code>rd</code></td><td style="text-align:left;">Supprimer un répertoire</td><td style="text-align:left;"><code>rd [directory]</code></td></tr><tr><td style="text-align:left;"><code>remove_disk</code></td><td style="text-align:left;">Éjecter un disque en toute sécurité</td><td style="text-align:left;"><code>remove_disk [disk]</code></td></tr></tbody></table><h3 id="divers" tabindex="-1">Divers <a class="header-anchor" href="#divers" aria-label="Permalink to &quot;Divers&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Fonction</th><th style="text-align:left;">Description</th><th style="text-align:left;">Utilisation</th></tr></thead><tbody><tr><td style="text-align:left;"><code>matrix</code></td><td style="text-align:left;">Effets Matrix dans le terminal</td><td style="text-align:left;"><code>matrix [options]</code></td></tr><tr><td style="text-align:left;"><code>prependpath</code></td><td style="text-align:left;">Ajouter un dossier au PATH</td><td style="text-align:left;"><code>prependpath [directory]</code></td></tr><tr><td style="text-align:left;"><code>ql</code></td><td style="text-align:left;">Ouvrir dans Quick Look (macOS)</td><td style="text-align:left;"><code>ql [file]</code></td></tr><tr><td style="text-align:left;"><code>vscode</code></td><td style="text-align:left;">Ouvrir dans VS Code</td><td style="text-align:left;"><code>vscode [file]</code></td></tr></tbody></table><h2 id="compatibilite" tabindex="-1">Compatibilité <a class="header-anchor" href="#compatibilite" aria-label="Permalink to &quot;Compatibilité&quot;">​</a></h2><ul><li><strong>macOS</strong> — Support complet avec utilitaires spécifiques</li><li><strong>Linux</strong> — Compatible avec les distributions courantes</li><li><strong>Windows</strong> — Support via WSL, Cygwin ou Git Bash</li></ul><h2 id="aide" tabindex="-1">Aide <a class="header-anchor" href="#aide" aria-label="Permalink to &quot;Aide&quot;">​</a></h2><p>Chaque fonction inclut une aide via <code>--help</code> :</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">apihealth</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --help</span></span></code></pre></div>',33)])])}const y=e(a,[["render",s]]);export{g as __pageData,y as default};
